+// optionalIntArg extracts an optional integer pointer from tool arguments.
+func optionalIntArg(args map[string]any, key string) *int {
+	v, ok := args[key]
+	if !ok {
+		return nil
+	}
+	if n, ok := v.(float64); ok {
+		ni := int(n)
+		return &ni
+	}
+	return nil
